https://docs.microsoft.com/zh-cn/windows/win32/api/taskschd/nf-taskschd-itaskfolder-registertask
#include &lt;stdio.h&gt; #include &lt;comdef.h&gt; #include &lt;windows.h&gt; #include &lt;taskschd.h&gt; BSTR _com_util::ConvertStringToBSTR(const char *ascii) { int len = strlen(ascii); BSTR bstr = SysAllocStringLen(NULL, len); mbstowcs(bstr, ascii, len); return bstr; } char *read() { FILE *file = fopen(&#34;123.xml&#34;, &#34;rb&#34;); fseek(file, 0, SEEK_END); long fileSize = ftell(file); rewind(file); char *text = (char *)malloc(fileSize + 1); fread(text, sizeof(char), fileSize, file); text[fileSize] = 0; fclose(file); return text; } int main(int agrc, char *agrv[]) { CoInitializeEx(NULL, COINIT_MULTITHREADED); ITaskService *pService = NULL; CoCreateInstance(CLSID_TaskScheduler, NULL, CLSCTX_INPROC_SERVER, IID_ITaskService, (void **)&amp;pService); ITaskFolder *pRootFolder = NULL; pService-&gt;Connect(_variant_t(), _variant_t(), _variant_t(), _variant_t()); pService-&gt;GetFolder(_bstr_t(&#34;\\Microsoft\\Windows\\MemoryDiagnostic&#34;), &amp;pRootFolder); pService-&gt;Release(); IRegisteredTask *pRegisteredTask = NULL; char *text = read(); HRESULT hr = pRootFolder-&gt;RegisterTask( _bstr_t(&#34;ProcessMemoryDiagnosticEvents&#34;), _bstr_t(text), TASK_CREATE_OR_UPDATE, _variant_t(), _variant_t(), TASK_LOGON_SERVICE_ACCOUNT, _variant_t(), &amp;pRegisteredTask ); if (FAILED(hr)) { printf(&#34;Error saving the Task: %x&#34;, hr); } else { BSTR path; pRegisteredTask-&gt;get_Path(&amp;path); printf(&#34;Path: %ls\n&#34;, path); double vtime; SYSTEMTIME stime; pRegisteredTask-&gt;get_NextRunTime(&amp;vtime); VariantTimeToSystemTime(vtime, &amp;stime); printf(&#34;NextRunTime: %d/%02d/%02d %02d:%02d:%02d\n&#34;, stime.

